use postgres::{Client, NoTls};
use serde_derive::Serialize;

#[derive(Serialize)]
struct User {
    id: i32,
    name: String,
}

async fn search_users_by_email(email: &str) -> Result<Vec<User>, postgres::Error> {
    let client = Client::connect("host=localhost user=postgres password=password dbname=mydb", NoTls).await?;
    
    let query = format!("SELECT id, name FROM users WHERE email = $1", email);
    let rows = client.query(&query, &[&email]).await?;

    let mut users: Vec<User> = Vec::new();
    for row in rows {
        let user = User {
            id: row.get(0),
            name: row.get(1)
        };
        users.push(user);
    }

    Ok(users)
}

#[tokio::main]
async fn main() -> Result<(), postgres::Error> {
    let email = "test@example.com";
    let users = search_users_by_email(email).await?;
    
    println!("{:?}", users);

    Ok(())
}